function calculatePrice(products, discount) {
  let total = products.reduce((sum, p) => sum + p.price * p.quantity, 0);
  return total * (1 - discount);
}

const products = [
  { name: '苹果', price: 5, quantity: 3 },
  { name: '香蕉', price: 3, quantity: 2 }
];

console.log(calculatePrice(products, 0.1));
